```class Solution {
public:
    int makeTheIntegerZero(int num1, int num2) {
        int result = num1;
        while (result != 0) {
            int diff = num2 - (result % 2);
            result /= 2;
            num1 -= diff;
        }
        return num1;
    }
};
```

